int main(void)
{
    int i;
    double sqrt_pi = sqrt(M_PI);

    /* (a) Hand-derived reference cases. */
    TEST_NEAR(gaunt_real(0,0,0,0,0,0), 1.0/(2*sqrt_pi), 1e-15);
    TEST_NEAR(gaunt_real(2,0,2,0,4,0), 1.0/sqrt(5*M_PI), 1e-14);
    TEST_NEAR(gaunt_real(2,2,2,2,0,0), 1.0/(2*sqrt_pi), 1e-14);
    TEST_NEAR(gaunt_real(2,-2,2,-2,0,0), 1.0/(2*sqrt_pi), 1e-14);
    TEST_NEAR(gaunt_real(4,4,4,4,0,0), 1.0/(2*sqrt_pi), 1e-14);
    /* parity / triangle violations and pairwise cancellations: */
    TEST_ABS(gaunt_real(2,0,2,0,2,0), 0.0, 1e-15);   /* l1+l2+l3 odd */
    TEST_ABS(gaunt_real(2,2,2,-2,0,0), 0.0, 1e-15);  /* cos*sin*1 vanishes */
    TEST_ABS(gaunt_real(2,2,2,2,0,0)-gaunt_real(2,2,2,2,0,0), 0.0, 1e-15);
    TEST_ABS(gaunt_real(2,-2,2,2,2,2), 0.0, 1e-15);  /* odd # of m_i<0 */

    /* (b) Permutation symmetry: G^R is symmetric in the 3 (l_i, m_i). */
    {
        double a = gaunt_real(2,0,4,2,4,-2);
        double b = gaunt_real(4,2,2,0,4,-2);
        double c = gaunt_real(4,-2,4,2,2,0);
        TEST_NEAR(a,b,1e-14);
        TEST_NEAR(a,c,1e-14);
    }

    /* (c) m=0: real Gaunt agrees with the complex Gaunt. */
    {
        const int cases[][3] = {
            {0,0,0},{2,2,0},{4,4,0},{2,2,4},{4,2,4},
            {6,4,4},{6,6,0},{6,6,4},{6,6,8},{8,8,8},
            {10,8,4},{12,12,0},{12,10,6},{20,16,4}
        };
        const int n = (int)(sizeof(cases)/sizeof(cases[0]));
        for (int j = 0; j < n; j++) {
            int l1 = cases[j][0], l2 = cases[j][1], l3 = cases[j][2];
            double r = gaunt_real(l1,0,l2,0,l3,0);
            double c = gaunt(l1,0,l2,0,l3,0);
            TEST_NEAR(r,c,1e-14);
        }
    }

    /* (d) sympy reference table */
    for (i = 0; i < (int)(sizeof(g_gaunt_real)/sizeof(g_gaunt_real[0])); i++) {
        const gaunt_real_t *c = &g_gaunt_real[i];
        double got = gaunt_real(c->tl1,c->tm1,c->tl2,c->tm2,c->tl3,c->tm3);
        TEST_NEAR(got, c->val, 1e-12);
    }

    SUMMARY();
}
